  1→//! Docker and Podman sandbox backends.
  2→
  3→use {
  4→    async_trait::async_trait,
  5→    std::collections::HashSet,
  6→    tokio::sync::Mutex,
  7→    tracing::{debug, info, warn},
  8→};
  9→
 10→use {
 11→    super::{
 12→        containers::{
 13→            rebuildable_sandbox_image_tag, sandbox_image_dockerfile, sandbox_image_exists,
 14→            sandbox_image_tag,
 15→        },
 16→        host::provision_packages,
 17→        paths::{
 18→            ensure_sandbox_home_persistence_host_dir, host_visible_data_dir,
 19→            resolve_home_persistence_guest_path_on_host, resolve_workspace_guest_path_on_host,
 20→        },
 21→        types::{
 22→            BuildImageResult, DEFAULT_SANDBOX_IMAGE, NetworkPolicy, SANDBOX_HOME_DIR, Sandbox,
 23→            SandboxConfig, SandboxId, WorkspaceMount, canonical_sandbox_packages, tail_lines,
 24→            truncate_output_for_display,
 25→        },
 26→    },
 27→    crate::{
 28→        error::{Error, Result},
 29→        exec::{ExecOpts, ExecResult},
 30→        sandbox::file_system::{
 31→            SandboxListFilesResult, SandboxReadResult, native_host_list_files,
 32→            native_host_read_file, native_host_write_file, oci_container_list_files,
 33→            oci_container_read_file, oci_container_write_file, remap_host_list_result_to_guest,
 34→        },
 35→    },
 36→};
 37→
 38→/// Distinguishes Docker from Podman for behaviour that differs between the two
 39→/// OCI runtimes (hardening flags, host-gateway resolution, etc.).
 40→#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 41→pub(crate) enum BackendKind {
 42→    Docker,
 43→    Podman,
 44→}
 45→
 46→/// Docker/Podman-based sandbox implementation.
 47→///
 48→/// The `cli` field selects the container CLI binary (`"docker"` or `"podman"`).
 49→/// Podman's CLI is a drop-in replacement for Docker, so both backends share
 50→/// this single implementation.  `kind` carries the typed backend identity for
 51→/// behaviour branching without string comparisons.
 52→pub struct DockerSandbox {
 53→    pub config: SandboxConfig,
 54→    kind: BackendKind,
 55→    cli: &'static str,
 56→    backend_label: &'static str,
 57→    /// Container names that have already been provisioned in this process.
 58→    /// Prevents repeated `apt-get install` runs on the same container.
 59→    pub(crate) provisioned: Mutex<HashSet<String>>,
 60→}
 61→
 62→impl DockerSandbox {
 63→    pub fn new(config: SandboxConfig) -> Self {
 64→        Self {
 65→            config,
 66→            kind: BackendKind::Docker,
 67→            cli: "docker",
 68→            backend_label: "docker",
 69→            provisioned: Mutex::new(HashSet::new()),
 70→        }
 71→    }
 72→
 73→    pub fn podman(config: SandboxConfig) -> Self {
 74→        Self {
 75→            config,
 76→            kind: BackendKind::Podman,
 77→            cli: "podman",
 78→            backend_label: "podman",
 79→            provisioned: Mutex::new(HashSet::new()),
 80→        }
 81→    }
 82→
 83→    fn image(&self) -> &str {
 84→        self.config
 85→            .image
 86→            .as_deref()
 87→            .unwrap_or(DEFAULT_SANDBOX_IMAGE)
 88→    }
 89→
 90→    fn container_prefix(&self) -> &str {
 91→        self.config
 92→            .container_prefix
 93→            .as_deref()
 94→            .unwrap_or("moltis-sandbox")
 95→    }
 96→
 97→    pub(crate) fn container_name(&self, id: &SandboxId) -> String {
 98→        format!("{}-{}", self.container_prefix(), id.key)
 99→    }
100→
101→    fn image_repo(&self) -> &str {
102→        self.container_prefix()
103→    }
104→
105→    fn mounted_host_path(&self, id: &SandboxId, guest_path: &str) -> Option<std::path::PathBuf> {
106→        let guest_path = std::path::Path::new(guest_path);
107→        resolve_workspace_guest_path_on_host(&self.config, Some(self.cli), guest_path).or_else(
108→            || {
109→                resolve_home_persistence_guest_path_on_host(
110→                    &self.config,
111→                    Some(self.cli),
112→                    id,
113→                    guest_path,
114→                )
115→            },
116→        )
117→    }
118→
119→    pub(crate) fn resource_args(&self) -> Vec<String> {
120→        let mut args = Vec::new();
121→        let limits = &self.config.resource_limits;
122→        if let Some(ref mem) = limits.memory_limit {
123→            args.extend(["--memory".to_string(), mem.clone()]);
124→        }
125→        if let Some(cpu) = limits.cpu_quota {
126→            args.extend(["--cpus".to_string(), cpu.to_string()]);
127→        }
128→        if let Some(pids) = limits.pids_max {
129→            args.extend(["--pids-limit".to_string(), pids.to_string()]);
130→        }
131→        args
132→    }
133→
134→    pub(crate) fn network_run_args(&self) -> Vec<String> {
135→        match self.config.network {
136→            NetworkPolicy::Blocked => vec!["--network=none".to_string()],
137→            NetworkPolicy::Trusted => {
138→                // Ensure the container can reach the host proxy on all
139→                // platforms (Linux needs --add-host; macOS Docker Desktop
140→                // resolves host.docker.internal automatically).
141→                let gateway = self.resolve_host_gateway();
142→                vec![format!("--add-host=host.docker.internal:{gateway}")]
143→            },
144→            NetworkPolicy::Bypass => Vec::new(),
145→        }
146→    }
147→
148→    /// Resolve the IP that containers use to reach the host.
149→    ///
150→    /// Docker (and Podman >= 5.0) support the special `host-gateway` token in
151→    /// `--add-host`.  Older Podman versions reject it with:
152→    ///
153→    ///   Error: invalid IP address in add-host: "host-gateway"
154→    ///
155→    /// For those we resolve the address ourselves: rootless Podman (< 5.0) uses
156→    /// slirp4netns by default, which maps the host to `10.0.2.2`.  Rootful
157→    /// Podman uses a bridge whose gateway we can query via
158→    /// `podman network inspect`.
159→    pub(crate) fn resolve_host_gateway(&self) -> String {
160→        if self.kind != BackendKind::Podman {
161→            return "host-gateway".to_string();
162→        }
163→
164→        if podman_supports_host_gateway() {
165→            return "host-gateway".to_string();
166→        }
167→
168→        // Podman < 5.0 — resolve the address manually.
169→        podman_resolve_host_ip().unwrap_or_else(|| {
170→            debug!(
171→                "could not resolve host gateway IP for podman; \
172→                 falling back to host-gateway (may fail)"
173→            );
174→            "host-gateway".to_string()
175→        })
176→    }
177→
178→    pub(crate) fn proxy_exec_env_args(&self) -> Vec<String> {
179→        if self.config.network != NetworkPolicy::Trusted {
180→            return Vec::new();
181→        }
182→        let proxy_url = format!(
183→            "http://host.docker.internal:{}",
184→            moltis_network_filter::DEFAULT_PROXY_PORT
185→        );
186→        let mut args = Vec::new();
187→        for key in ["HTTP_PROXY", "http_proxy", "HTTPS_PROXY", "https_proxy"] {
188→            args.extend(["-e".to_string(), format!("{key}={proxy_url}")]);
189→        }
190→        for key in ["NO_PROXY", "no_proxy"] {
191→            args.extend(["-e".to_string(), format!("{key}=localhost,127.0.0.1,::1")]);
192→        }
193→        args
194→    }
195→
196→    /// Security hardening flags for `docker run`.
197→    ///
198→    /// `is_prebuilt` controls whether `--read-only` is applied: prebuilt images
199→    /// already have packages baked in so the root FS can be read-only, while
200→    /// non-prebuilt images need a writable root for `apt-get` provisioning.
201→    pub(crate) fn hardening_args(is_prebuilt: bool, kind: BackendKind) -> Vec<String> {
202→        let mut args = vec![
203→            // --- Capability / privilege ---
204→            "--cap-drop".to_string(),
205→            "ALL".to_string(),
206→            "--security-opt".to_string(),
207→            "no-new-privileges".to_string(),
208→            // --- Writable tmpfs mounts ---
209→            "--tmpfs".to_string(),
210→            "/tmp:rw,nosuid,size=256m".to_string(),
211→            "--tmpfs".to_string(),
212→            "/run:rw,nosuid,size=64m".to_string(),
213→            // --- Host metadata isolation ---
214→            // Give the container its own hostname so /proc/sys/kernel/hostname
215→            // and the `hostname` command do not reveal the host identity.
216→            "--hostname".to_string(),
217→            "sandbox".to_string(),
218→        ];
219→        // Mask /sys subtrees that expose host hardware identifiers
220→        // (serial numbers, BIOS/UEFI data, disk models, LUKS UUIDs).
221→        // Empty read-only tmpfs overlays hide the underlying sysfs entries.
222→        //
223→        // Podman is excluded: its OCI runtime performs "tmpcopyup" on sysfs
224→        // tmpfs mounts, copying directory contents into the tmpfs first.
225→        // With --cap-drop ALL some sysfs files are permission-denied even for
226→        // root, causing the mount (and container startup) to fail.  Podman
227→        // already masks /sys/firmware via its built-in OCI MaskedPaths.
228→        if kind != BackendKind::Podman {
229→            args.extend([
230→                "--tmpfs".to_string(),
231→                "/sys/firmware:ro,nosuid".to_string(),
232→                "--tmpfs".to_string(),
233→                "/sys/class/dmi:ro,nosuid".to_string(),
234→                "--tmpfs".to_string(),
235→                "/sys/devices/virtual/dmi:ro,nosuid".to_string(),
236→                "--tmpfs".to_string(),
237→                "/sys/class/block:ro,nosuid".to_string(),
238→            ]);
239→        }
240→        if is_prebuilt {
241→            args.push("--read-only".to_string());
242→        }
243→        args
244→    }
245→
246→    pub(crate) fn workspace_args(&self) -> Vec<String> {
247→        let guest_workspace_dir = moltis_config::data_dir();
248→        let host_workspace_dir = host_visible_data_dir(&self.config, Some(self.cli));
249→        let guest_workspace_dir_str = guest_workspace_dir.display().to_string();
250→        let host_workspace_dir_str = host_workspace_dir.display().to_string();
251→        match self.config.workspace_mount {
252→            WorkspaceMount::Ro => vec![
253→                "-v".to_string(),
254→                format!("{host_workspace_dir_str}:{guest_workspace_dir_str}:ro"),
255→            ],
256→            WorkspaceMount::Rw => vec![
257→                "-v".to_string(),
258→                format!("{host_workspace_dir_str}:{guest_workspace_dir_str}:rw"),
259→            ],
260→            WorkspaceMount::None => Vec::new(),
261→        }
262→    }
263→
264→    pub(crate) fn home_persistence_args(&self, id: &SandboxId) -> Result<Vec<String>> {
265→        let Some(host_dir) =
266→            ensure_sandbox_home_persistence_host_dir(&self.config, Some(self.cli), id)?
267→        else {
268→            return Ok(Vec::new());
269→        };
270→        let volume = format!("{}:{SANDBOX_HOME_DIR}:rw", host_dir.display());
271→        Ok(vec!["-v".to_string(), volume])
272→    }
273→
274→    async fn resolve_local_image(&self, requested_image: &str) -> Result<String> {
275→        if sandbox_image_exists(self.cli, requested_image).await {
276→            debug!(image = requested_image, "sandbox image found locally");
277→            return Ok(requested_image.to_string());
278→        }
279→
280→        let base_image = self.image().to_string();
281→        let packages = self.config.packages.clone();
282→        let Some(rebuild_tag) = rebuildable_sandbox_image_tag(
283→            requested_image,
284→            self.image_repo(),
285→            &base_image,
286→            &packages,
287→        ) else {
288→            return Ok(requested_image.to_string());
289→        };
290→
291→        if requested_image == rebuild_tag {
292→            info!(
293→                image = requested_image,
294→                "sandbox image missing locally, rebuilding on demand"
295→            );
296→        } else {
297→            warn!(
298→                requested = requested_image,
299→                rebuilt = %rebuild_tag,
300→                "requested sandbox image missing locally, using deterministic tag from current config"
301→            );
302→        }
303→
304→        let Some(result) = self.build_image(&base_image, &packages).await? else {
305→            return Ok(requested_image.to_string());
306→        };
307→        Ok(result.tag)
308→    }
309→}
310→
311→#[async_trait]
312→impl Sandbox for DockerSandbox {
313→    fn backend_name(&self) -> &'static str {
314→        self.backend_label
315→    }
316→
317→    async fn ensure_ready(&self, id: &SandboxId, image_override: Option<&str>) -> Result<()> {
318→        let name = self.container_name(id);
319→
320→        // Check if container already running.
321→        let check = tokio::process::Command::new(self.cli)
322→            .args(["inspect", "--format", "{{.State.Running}}", &name])
323→            .output()
324→            .await;
325→
326→        if let Ok(output) = check {
327→            let stdout = String::from_utf8_lossy(&output.stdout);
328→            if stdout.trim() == "true" {
329→                debug!(container = %name, "sandbox container already running");
330→                return Ok(());
331→            }
332→        }
333→
334→        // Resolve image first so we know whether it's prebuilt (affects hardening).
335→        let requested_image = image_override.unwrap_or_else(|| self.image());
336→        let image = self.resolve_local_image(requested_image).await?;
337→        let is_prebuilt = image.starts_with(&format!("{}:", self.image_repo()));
338→        debug!(container = %name, %image, is_prebuilt, "resolved sandbox image");
339→
340→        // Start a new container.
341→        info!(container = %name, %image, "starting new sandbox container");
342→        let mut args = vec![
343→            "run".to_string(),
344→            "-d".to_string(),
345→            "--name".to_string(),
346→            name.clone(),
347→        ];
348→
349→        args.extend(self.network_run_args());
350→
351→        if let Some(ref tz) = self.config.timezone {
352→            args.extend(["-e".to_string(), format!("TZ={tz}")]);
353→        }
354→
355→        args.extend(self.resource_args());
356→        args.extend(Self::hardening_args(is_prebuilt, self.kind));
357→        args.extend(self.workspace_args());
358→        args.extend(self.home_persistence_args(id)?);
359→
360→        args.push(image.clone());
361→        args.extend(["sleep".to_string(), "infinity".to_string()]);
362→
363→        let output = tokio::process::Command::new(self.cli)
364→            .args(&args)
365→            .output()
366→            .await?;
367→
368→        if !output.status.success() {
369→            let stderr = String::from_utf8_lossy(&output.stderr);
370→            return Err(Error::message(format!(
371→                "{} run failed: {}",
372→                self.cli,
373→                stderr.trim()
374→            )));
375→        }
376→
377→        // Skip provisioning if the image is a pre-built instance sandbox image
378→        // (packages are already baked in — including /home/sandbox from the Dockerfile).
379→        if !is_prebuilt {
380→            let needs_provisioning = {
381→                let mut provisioned = self.provisioned.lock().await;
382→                if provisioned.contains(&name) {
383→                    false
384→                } else {
385→                    provisioned.insert(name.clone());
386→                    true
387→                }
388→            };
389→            if needs_provisioning {
390→                if let Err(e) = provision_packages(self.cli, &name, &self.config.packages).await {
391→                    self.provisioned.lock().await.remove(&name);
392→                    return Err(e);
393→                }
394→            } else {
395→                debug!(
396→                    container = %name,
397→                    "skipping provisioning, already completed for container"
398→                );
399→            }
400→        }
401→
402→        Ok(())
403→    }
404→
405→    async fn build_image(
406→        &self,
407→        base: &str,
408→        packages: &[String],
409→    ) -> Result<Option<BuildImageResult>> {
410→        if packages.is_empty() {
411→            return Ok(None);
412→        }
413→
414→        let tag = sandbox_image_tag(self.image_repo(), base, packages);
415→
416→        // Check if image already exists.
417→        if sandbox_image_exists(self.cli, &tag).await {
418→            info!(
419→                tag,
420→                "pre-built sandbox image already exists, skipping build"
421→            );
422→            return Ok(Some(BuildImageResult { tag, built: false }));
423→        }
424→
425→        // Generate Dockerfile in a temp dir.
426→        let tmp_dir =
427→            std::env::temp_dir().join(format!("moltis-sandbox-build-{}", uuid::Uuid::new_v4()));
428→        std::fs::create_dir_all(&tmp_dir)?;
429→
430→        let pkg_list = canonical_sandbox_packages(packages).join(" ");
431→        let dockerfile = sandbox_image_dockerfile(base, packages);
432→        let dockerfile_path = tmp_dir.join("Dockerfile");
433→        std::fs::write(&dockerfile_path, &dockerfile)?;
434→
435→        info!(tag, packages = %pkg_list, "building pre-built sandbox image");
436→
437→        let output = tokio::process::Command::new(self.cli)
438→            .args(["build", "-t", &tag, "-f"])
439→            .arg(&dockerfile_path)
440→            .arg(&tmp_dir)
441→            .stdout(std::process::Stdio::piped())
442→            .stderr(std::process::Stdio::piped())
443→            .output()
444→            .await;
445→
446→        // Clean up temp dir regardless of result.
447→        let _ = std::fs::remove_dir_all(&tmp_dir);
448→
449→        let output = output?;
450→        if !output.status.success() {
451→            let stdout = String::from_utf8_lossy(&output.stdout);
452→            let stderr = String::from_utf8_lossy(&output.stderr);
453→            warn!(
454→                tag,
455→                stdout = %tail_lines(&stdout, 20),
456→                stderr = %stderr.trim(),
457→                "{} build failed",
458→                self.cli,
459→            );
460→            return Err(Error::message(format!(
461→                "{} build failed for {tag}: {}",
462→                self.cli,
463→                stderr.trim()
464→            )));
465→        }
466→
467→        let stdout = String::from_utf8_lossy(&output.stdout);
468→        debug!(tag, output = %tail_lines(&stdout, 20), "docker build output");
469→        info!(tag, "pre-built sandbox image ready");
470→        Ok(Some(BuildImageResult { tag, built: true }))
471→    }
472→
473→    async fn exec(&self, id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
474→        let name = self.container_name(id);
475→
476→        let mut args = vec!["exec".to_string()];
477→
478→        if let Some(ref dir) = opts.working_dir {
479→            args.extend(["-w".to_string(), dir.display().to_string()]);
480→        }
481→
482→        // Inject proxy env vars so traffic routes through the trusted-network
483→        // proxy running on the host.
484→        args.extend(self.proxy_exec_env_args());
485→
486→        for (k, v) in &opts.env {
487→            args.extend(["-e".to_string(), format!("{}={}", k, v)]);
488→        }
489→
490→        args.push(name);
491→        args.extend(["sh".to_string(), "-c".to_string(), command.to_string()]);
492→
493→        let child = tokio::process::Command::new(self.cli)
494→            .args(&args)
495→            .stdout(std::process::Stdio::piped())
496→            .stderr(std::process::Stdio::piped())
497→            .stdin(std::process::Stdio::null())
498→            .spawn()?;
499→
500→        let result = tokio::time::timeout(opts.timeout, child.wait_with_output()).await;
501→
502→        match result {
503→            Ok(Ok(output)) => {
504→                let mut stdout = String::from_utf8_lossy(&output.stdout).into_owned();
505→                let mut stderr = String::from_utf8_lossy(&output.stderr).into_owned();
506→
507→                truncate_output_for_display(&mut stdout, opts.max_output_bytes);
508→                truncate_output_for_display(&mut stderr, opts.max_output_bytes);
509→
510→                Ok(ExecResult {
511→                    stdout,
512→                    stderr,
513→                    exit_code: output.status.code().unwrap_or(-1),
514→                })
515→            },
516→            Ok(Err(e)) => {
517→                return Err(Error::message(format!("{} exec failed: {e}", self.cli)));
518→            },
519→            Err(_) => {
520→                return Err(Error::message(format!(
521→                    "{} exec timed out after {}s",
522→                    self.cli,
523→                    opts.timeout.as_secs()
524→                )));
525→            },
526→        }
527→    }
528→
529→    async fn read_file(
530→        &self,
531→        id: &SandboxId,
532→        file_path: &str,
533→        max_bytes: u64,
534→    ) -> Result<SandboxReadResult> {
535→        if let Some(host_path) = self.mounted_host_path(id, file_path) {
536→            return native_host_read_file(
537→                host_path
538→                    .to_str()
539→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
540→                max_bytes,
541→            )
542→            .await;
543→        }
544→
545→        let container_name = self.container_name(id);
546→        oci_container_read_file(self.cli, &container_name, file_path, max_bytes).await
547→    }
548→
549→    async fn write_file(
550→        &self,
551→        id: &SandboxId,
552→        file_path: &str,
553→        content: &[u8],
554→    ) -> Result<Option<serde_json::Value>> {
555→        if let Some(host_path) = self.mounted_host_path(id, file_path) {
556→            return native_host_write_file(
557→                host_path
558→                    .to_str()
559→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
560→                content,
561→            )
562→            .await;
563→        }
564→
565→        let container_name = self.container_name(id);
566→        oci_container_write_file(self.cli, &container_name, file_path, content).await
567→    }
568→
569→    async fn list_files(&self, id: &SandboxId, root: &str) -> Result<SandboxListFilesResult> {
570→        if let Some(host_path) = self.mounted_host_path(id, root) {
571→            let host_files = native_host_list_files(
572→                host_path
573→                    .to_str()
574→                    .ok_or_else(|| Error::message("mounted host path contains invalid UTF-8"))?,
575→            )
576→            .await?;
577→            return remap_host_list_result_to_guest(root, &host_path, host_files);
578→        }
579→
580→        let container_name = self.container_name(id);
581→        oci_container_list_files(self.cli, &container_name, root).await
582→    }
583→
584→    async fn cleanup(&self, id: &SandboxId) -> Result<()> {
585→        let name = self.container_name(id);
586→        self.provisioned.lock().await.remove(&name);
587→        let _ = tokio::process::Command::new(self.cli)
588→            .args(["rm", "-f", &name])
589→            .output()
590→            .await;
591→        Ok(())
592→    }
593→}
