595→/// No-op sandbox that passes through to direct execution.
596→pub struct NoSandbox;
597→
598→#[async_trait]
599→impl Sandbox for NoSandbox {
600→    fn backend_name(&self) -> &'static str {
601→        "none"
602→    }
603→
604→    fn is_real(&self) -> bool {
605→        false
606→    }
607→
608→    async fn ensure_ready(&self, _id: &SandboxId, _image_override: Option<&str>) -> Result<()> {
609→        Ok(())
610→    }
611→
612→    async fn exec(&self, _id: &SandboxId, command: &str, opts: &ExecOpts) -> Result<ExecResult> {
613→        crate::exec::exec_command(command, opts).await
614→    }
615→
616→    async fn read_file(
617→        &self,
618→        _id: &SandboxId,
619→        file_path: &str,
620→        max_bytes: u64,
621→    ) -> Result<SandboxReadResult> {
622→        native_host_read_file(file_path, max_bytes).await
623→    }
