625→    async fn write_file(
626→        &self,
627→        _id: &SandboxId,
628→        file_path: &str,
629→        content: &[u8],
630→    ) -> Result<Option<serde_json::Value>> {
631→        native_host_write_file(file_path, content).await
632→    }
