647→        .args(["version", "--format", "{{.Client.Version}}"])
648→        .output()
649→    else {
650→        return false;
651→    };
652→    let version_str = String::from_utf8_lossy(&output.stdout);
653→    let major: u32 = version_str
654→        .trim()
655→        .split('.')
656→        .next()
657→        .and_then(|s| s.parse().ok())
658→        .unwrap_or(0);
