121→/// Compute the content-hash tag for a pre-built sandbox image.
122→/// Pure function — independent of any specific container CLI.
123→pub fn sandbox_image_tag(repo: &str, base: &str, packages: &[String]) -> String {
124→    let dockerfile = sandbox_image_dockerfile(base, packages);
125→    let digest = Sha256::digest(dockerfile.as_bytes());
126→    format!("{repo}:{digest:x}")
127→}
