136→/// Return the deterministic image tag for the current sandbox config when the
137→/// requested image points to a local pre-built sandbox repository.
138→///
139→/// This allows recover-on-demand behavior when users delete local pre-built
140→/// images from the UI while Moltis is still running.
141→pub(crate) fn rebuildable_sandbox_image_tag(
142→    requested_image: &str,
143→    image_repo: &str,
144→    base_image: &str,
145→    packages: &[String],
146→) -> Option<String> {
147→    if packages.is_empty() {
148→        return None;
149→    }
150→    if !requested_image.starts_with(&format!("{image_repo}:")) {
151→        return None;
152→    }
153→    Some(sandbox_image_tag(image_repo, base_image, packages))
154→}
