156→/// OCI-compatible CLI binaries that use Docker-format commands
157→/// (`image ls`, `ps`, `system df`, etc.).
158→pub(crate) const OCI_COMPATIBLE_CLIS: &[&str] = &["docker", "podman"];
159→
160→/// Check whether a container image exists locally.
161→/// `cli` is the container CLI binary (e.g. `"docker"`, `"podman"`, or `"container"`).
162→pub(crate) async fn sandbox_image_exists(cli: &str, tag: &str) -> bool {
163→    tokio::process::Command::new(cli)
164→        .args(["image", "inspect", tag])
165→        .stdout(std::process::Stdio::null())
166→        .stderr(std::process::Stdio::null())
167→        .status()
168→        .await
169→        .is_ok_and(|s| s.success())
170→}
171→
172→/// Information about a locally cached sandbox image.
173→#[derive(Debug, Clone)]
174→pub struct SandboxImage {
175→    pub tag: String,
176→    pub size: String,
177→    pub created: String,
178→}
179→
180→/// List all local `<instance>-sandbox:*` images across available container CLIs.
181→pub async fn list_sandbox_images() -> Result<Vec<SandboxImage>> {
182→    let mut images = Vec::new();
183→    let mut seen = HashSet::new();
184→
185→    // Docker/Podman: both support --format with Go templates.
186→    for cli in OCI_COMPATIBLE_CLIS {
187→        if !is_cli_available(cli) {
188→            continue;
189→        }
190→        let output = tokio::process::Command::new(cli)
191→            .args([
192→                "image",
193→                "ls",
194→                "--format",
195→                "{{.Repository}}:{{.Tag}}\t{{.Size}}\t{{.CreatedSince}}",
196→            ])
197→            .output()
198→            .await?;
199→        if output.status.success() {
200→            let stdout = String::from_utf8_lossy(&output.stdout);
201→            for line in stdout.lines() {
202→                let parts: Vec<&str> = line.splitn(3, '\t').collect();
203→                if parts.len() != 3 {
204→                    continue;
205→                }
206→                // Podman prefixes local repos with "localhost/"; normalize.
207→                let tag = parts[0].strip_prefix("localhost/").unwrap_or(parts[0]);
208→                if is_sandbox_image_tag(tag) && seen.insert(tag.to_string()) {
209→                    images.push(SandboxImage {
210→                        tag: tag.to_string(),
211→                        size: parts[1].to_string(),
212→                        created: parts[2].to_string(),
213→                    });
214→                }
215→            }
216→        }
217→    }
218→
219→    // Apple Container: fixed table output (NAME  TAG  DIGEST), no --format.
220→    // Parse the table, then use `image inspect` JSON for metadata.
221→    if is_cli_available("container") {
222→        let output = tokio::process::Command::new("container")
223→            .args(["image", "ls"])
224→            .output()
225→            .await?;
226→        if output.status.success() {
227→            let stdout = String::from_utf8_lossy(&output.stdout);
228→            for line in stdout.lines().skip(1) {
229→                // Columns are whitespace-separated: NAME TAG DIGEST
230→                let cols: Vec<&str> = line.split_whitespace().collect();
231→                if cols.len() >= 2 && cols[0].ends_with("-sandbox") {
232→                    let tag = format!("{}:{}", cols[0], cols[1]);
233→                    if !seen.insert(tag.clone()) {
234→                        continue;
235→                    }
236→                    // Fetch size and created from inspect JSON.
237→                    let (size, created) = inspect_apple_container_image(&tag).await;
238→                    images.push(SandboxImage { tag, size, created });
239→                }
240→            }
241→        }
242→    }
243→
244→    Ok(images)
245→}
246→
247→/// Extract size and created timestamp from Apple Container `image inspect` JSON.
248→async fn inspect_apple_container_image(tag: &str) -> (String, String) {
249→    let output = tokio::process::Command::new("container")
250→        .args(["image", "inspect", tag])
251→        .output()
252→        .await;
253→    let fallback = ("—".to_string(), "—".to_string());
254→    let Ok(output) = output else {
255→        return fallback;
256→    };
257→    if !output.status.success() {
258→        return fallback;
259→    }
260→    let Ok(json): std::result::Result<serde_json::Value, _> =
261→        serde_json::from_slice(&output.stdout)
262→    else {
263→        return fallback;
264→    };
265→    let entry = json.as_array().and_then(|a| a.first());
266→    let Some(entry) = entry else {
267→        return fallback;
268→    };
269→    let created = entry
270→        .pointer("/index/annotations/org.opencontainers.image.created")
271→        .and_then(|v| v.as_str())
272→        .unwrap_or("—")
273→        .to_string();
274→    let size = entry
275→        .pointer("/variants/0/size")
276→        .and_then(|v| v.as_u64())
277→        .map(format_bytes)
278→        .unwrap_or_else(|| "—".to_string());
279→    (size, created)
280→}
281→
282→/// Format a byte count as a human-readable string (e.g. "361 MB").
283→pub(crate) fn format_bytes(bytes: u64) -> String {
284→    const KB: u64 = 1024;
285→    const MB: u64 = 1024 * KB;
286→    const GB: u64 = 1024 * MB;
287→    if bytes >= GB {
288→        format!("{:.1} GB", bytes as f64 / GB as f64)
289→    } else if bytes >= MB {
290→        format!("{:.0} MB", bytes as f64 / MB as f64)
291→    } else if bytes >= KB {
292→        format!("{:.0} KB", bytes as f64 / KB as f64)
293→    } else {
294→        format!("{bytes} B")
295→    }
296→}
297→
298→/// Remove a specific `<instance>-sandbox:*` image.
299→pub async fn remove_sandbox_image(tag: &str) -> Result<()> {
300→    if !is_sandbox_image_tag(tag) {
301→        return Err(Error::message(format!(
302→            "refusing to remove non-sandbox image: {tag}"
303→        )));
304→    }
305→    // OCI-compatible CLIs (docker, podman) + Apple Container.
306→    let all_clis: Vec<&str> = OCI_COMPATIBLE_CLIS
307→        .iter()
308→        .copied()
309→        .chain(std::iter::once("container"))
310→        .collect();
311→    for cli in &all_clis {
312→        if !is_cli_available(cli) {
313→            continue;
314→        }
315→        if sandbox_image_exists(cli, tag).await {
316→            // Apple Container uses `image delete`, Docker/Podman use `image rm`.
317→            let subcmd = if *cli == "container" {
318→                "delete"
319→            } else {
320→                "rm"
321→            };
322→            let output = tokio::process::Command::new(cli)
323→                .args(["image", subcmd, tag])
324→                .output()
325→                .await?;
326→            if !output.status.success() {
327→                let stderr = String::from_utf8_lossy(&output.stderr);
328→                return Err(Error::message(format!(
329→                    "{cli} image {subcmd} failed for {tag}: {}",
330→                    stderr.trim()
331→                )));
332→            }
333→        }
334→    }
335→    Ok(())
336→}
337→
338→/// Remove all local `<instance>-sandbox:*` images.
339→pub async fn clean_sandbox_images() -> Result<usize> {
340→    let images = list_sandbox_images().await?;
341→    let count = images.len();
342→    for img in &images {
343→        remove_sandbox_image(&img.tag).await?;
344→    }
345→    Ok(count)
346→}
