348→// ── Running container management ─────────────────────────────────────────────
349→
350→/// State of a running/stopped container.
351→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize)]
352→#[serde(rename_all = "lowercase")]
353→pub enum ContainerRunState {
354→    Running,
355→    Stopped,
356→    Exited,
357→    Unknown,
358→}
359→
360→/// Which container backend manages this container.
361→#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize)]
362→#[serde(rename_all = "kebab-case")]
363→pub enum ContainerBackend {
364→    AppleContainer,
365→    Docker,
366→    Podman,
367→}
368→
369→/// A container managed by moltis (running, stopped, or exited).
370→#[derive(Debug, Clone, Serialize)]
371→pub struct RunningContainer {
372→    pub name: String,
373→    pub image: String,
374→    pub state: ContainerRunState,
375→    pub backend: ContainerBackend,
376→    pub cpus: Option<u32>,
377→    pub memory_mb: Option<u64>,
378→    pub started: Option<String>,
379→    pub addr: Option<String>,
380→}
381→
382→/// Containers that failed removal but are no longer truly present in the
383→/// runtime. These ghosts appear in `container list` after a failed
384→/// `container rm -f` and cannot be deleted until the daemon restarts.
385→/// Filtering them out of list results gives the UI a consistent view.
386→static ZOMBIE_CONTAINERS: std::sync::LazyLock<std::sync::RwLock<HashSet<String>>> =
387→    std::sync::LazyLock::new(|| std::sync::RwLock::new(HashSet::new()));
388→
389→pub(crate) fn mark_zombie(name: &str) {
390→    if let Ok(mut set) = ZOMBIE_CONTAINERS.write() {
391→        set.insert(name.to_string());
392→    }
393→}
394→
395→pub(crate) fn unmark_zombie(name: &str) {
396→    if let Ok(mut set) = ZOMBIE_CONTAINERS.write() {
397→        set.remove(name);
398→    }
399→}
400→
401→pub(crate) fn clear_zombies() {
402→    if let Ok(mut set) = ZOMBIE_CONTAINERS.write() {
403→        set.clear();
404→    }
405→}
406→
407→pub(crate) fn is_zombie(name: &str) -> bool {
408→    ZOMBIE_CONTAINERS
409→        .read()
410→        .map(|set| set.contains(name))
411→        .unwrap_or(false)
412→}
413→
414→/// List all containers whose name starts with `container_prefix`.
415→///
416→/// Queries both Apple Container and Docker backends when available,
417→/// merging results with the appropriate backend label.
418→pub async fn list_running_containers(container_prefix: &str) -> Result<Vec<RunningContainer>> {
419→    let mut containers = Vec::new();
420→    let mut seen = HashSet::new();
421→
422→    // Apple Container: `container list --format json` outputs a JSON array.
423→    // Each element has nested fields: configuration.id, status,
424→    // configuration.image.reference, configuration.resources, networks[].
425→    if is_cli_available("container") {
426→        let output = tokio::process::Command::new("container")
427→            .args(["list", "--format", "json"])
428→            .output()
429→            .await;
430→        if let Ok(output) = output
431→            && output.status.success()
432→        {
433→            let stdout = String::from_utf8_lossy(&output.stdout);
434→            let entries: Vec<serde_json::Value> = serde_json::from_str(&stdout).unwrap_or_default();
435→            for entry in entries {
436→                let name = entry
437→                    .pointer("/configuration/id")
438→                    .and_then(|v| v.as_str())
439→                    .unwrap_or_default();
440→                if !name.starts_with(container_prefix) || !seen.insert(name.to_string()) {
441→                    continue;
442→                }
443→                let state_str = entry
444→                    .get("status")
445→                    .and_then(|v| v.as_str())
446→                    .unwrap_or_default();
447→                let state = match state_str {
448→                    "running" => ContainerRunState::Running,
449→                    "stopped" => ContainerRunState::Stopped,
450→                    "exited" => ContainerRunState::Exited,
451→                    _ => ContainerRunState::Unknown,
452→                };
453→                let image = entry
454→                    .pointer("/configuration/image/reference")
455→                    .and_then(|v| v.as_str())
456→                    .unwrap_or_default()
457→                    .to_string();
458→                let cpus = entry
459→                    .pointer("/configuration/resources/cpus")
460→                    .and_then(|v| v.as_u64())
461→                    .map(|v| v as u32);
462→                let memory_mb = entry
463→                    .pointer("/configuration/resources/memoryInBytes")
464→                    .and_then(|v| v.as_u64())
465→                    .map(|v| v / (1024 * 1024));
466→                // startedDate is a Core Foundation absolute time (seconds since 2001-01-01).
467→                // Store as unix timestamp string; the frontend formats for display.
468→                let started =
469→                    entry
470→                        .get("startedDate")
471→                        .and_then(|v| v.as_f64())
472→                        .map(|cf_timestamp| {
473→                            // CF absolute time epoch: 2001-01-01T00:00:00Z = 978307200 unix seconds.
474→                            let unix_secs = cf_timestamp as i64 + 978_307_200;
475→                            unix_secs.to_string()
476→                        });
477→                let addr = entry
478→                    .pointer("/networks/0/ipv4Address")
479→                    .and_then(|v| v.as_str())
480→                    .map(String::from);
481→
482→                containers.push(RunningContainer {
483→                    name: name.to_string(),
484→                    image,
485→                    state,
486→                    backend: ContainerBackend::AppleContainer,
487→                    cpus,
488→                    memory_mb,
489→                    started,
490→                    addr,
491→                });
492→            }
493→        }
494→    }
495→
496→    // Docker/Podman: `<cli> ps -a --filter name=<prefix> --format json` outputs one JSON per line.
497→    for (cli, backend) in OCI_COMPATIBLE_CLIS
498→        .iter()
499→        .zip([ContainerBackend::Docker, ContainerBackend::Podman])
500→    {
501→        if !is_cli_available(cli) {
502→            continue;
503→        }
504→        let output = tokio::process::Command::new(cli)
505→            .args([
506→                "ps",
507→                "-a",
508→                "--filter",
509→                &format!("name={container_prefix}"),
510→                "--format",
511→                "{{json .}}",
512→            ])
513→            .output()
514→            .await;
515→        if let Ok(output) = output
516→            && output.status.success()
517→        {
518→            let stdout = String::from_utf8_lossy(&output.stdout);
519→            for line in stdout.lines() {
520→                let line = line.trim();
521→                if line.is_empty() {
522→                    continue;
523→                }
524→                let Ok(json): std::result::Result<serde_json::Value, _> =
525→                    serde_json::from_str(line)
526→                else {
527→                    continue;
528→                };
529→                let name = json
530→                    .get("Names")
531→                    .and_then(|v| v.as_str())
532→                    .unwrap_or_default();
533→                if !name.starts_with(container_prefix) || !seen.insert(name.to_string()) {
534→                    continue;
535→                }
536→                let state_str = json
537→                    .get("State")
538→                    .and_then(|v| v.as_str())
539→                    .unwrap_or_default();
540→                let state = match state_str {
541→                    "running" => ContainerRunState::Running,
542→                    "exited" => ContainerRunState::Exited,
543→                    _ => ContainerRunState::Stopped,
544→                };
545→                let image = json
546→                    .get("Image")
547→                    .and_then(|v| v.as_str())
548→                    .unwrap_or_default()
549→                    .to_string();
550→                let started = json
551→                    .get("CreatedAt")
552→                    .and_then(|v| v.as_str())
553→                    .map(String::from);
554→
555→                containers.push(RunningContainer {
556→                    name: name.to_string(),
557→                    image,
558→                    state,
559→                    backend,
560→                    cpus: None,
561→                    memory_mb: None,
562→                    started,
563→                    addr: None,
564→                });
565→            }
566→        }
567→    }
568→
569→    containers.retain(|c| !is_zombie(&c.name));
570→    Ok(containers)
571→}
