677→/// Remove all containers whose name starts with `container_prefix`.
678→///
679→/// Returns the number of containers removed.
680→pub async fn clean_all_containers(container_prefix: &str) -> Result<usize> {
681→    let containers = list_running_containers(container_prefix).await?;
682→    let mut removed = 0;
683→    for c in &containers {
684→        // Stop running containers first.
685→        if c.state == ContainerRunState::Running {
686→            let _ = stop_container(&c.name).await;
687→        }
688→        match remove_container(&c.name).await {
689→            Ok(()) => removed += 1,
690→            Err(e) => {
691→                warn!(name = %c.name, %e, "failed to remove container during clean all");
692→            },
693→        }
694→    }
695→    Ok(removed)
696→}
697→
698→/// Stop a container by name. Detects the backend from the available CLIs.
699→///
700→/// Safety: callers must validate that `name` starts with the expected prefix
701→/// to prevent stopping arbitrary containers.
702→pub async fn stop_container(name: &str) -> Result<()> {
703→    // Try Apple Container first, then Docker/Podman.
704→    if is_cli_available("container") {
705→        let output = tokio::process::Command::new("container")
706→            .args(["stop", name])
707→            .output()
708→            .await;
709→        if let Ok(ref o) = output
710→            && o.status.success()
711→        {
712→            return Ok(());
713→        }
714→    }
715→    for cli in OCI_COMPATIBLE_CLIS {
716→        if !is_cli_available(cli) {
717→            continue;
718→        }
719→        let output = tokio::process::Command::new(cli)
720→            .args(["stop", name])
721→            .output()
722→            .await?;
723→        if !output.status.success() {
724→            let stderr = String::from_utf8_lossy(&output.stderr);
725→            return Err(Error::message(format!(
726→                "{cli} stop failed for {name}: {}",
727→                stderr.trim()
728→            )));
729→        }
730→        return Ok(());
731→    }
732→    Err(Error::message(format!(
733→        "no container CLI available to stop {name}"
734→    )))
735→}
736→
737→/// Remove a container by name (force). Detects the backend from available CLIs.
738→///
739→/// Safety: callers must validate that `name` starts with the expected prefix
740→/// to prevent removing arbitrary containers.
741→pub async fn remove_container(name: &str) -> Result<()> {
742→    // Try Apple Container first, then Docker.
743→    if is_cli_available("container") {
744→        let output = tokio::process::Command::new("container")
745→            .args(["rm", "-f", name])
746→            .output()
747→            .await;
748→        if let Ok(ref o) = output
749→            && o.status.success()
750→        {
751→            unmark_zombie(name);
752→            return Ok(());
753→        }
754→
755→        // rm failed — inspect to classify the ghost container.
756→        let inspect = tokio::process::Command::new("container")
757→            .args(["inspect", name, "--format", "json"])
758→            .output()
759→            .await;
760→        match inspect {
761→            Ok(ref ins) if ins.status.success() => {
762→                let stdout = String::from_utf8_lossy(&ins.stdout);
763→                let status = apple_container_status_from_inspect(&stdout);
764→                if status == Some("running") {
765→                    // Container is genuinely running — return the rm error.
766→                    let stderr = output
767→                        .as_ref()
768→                        .map(|o| String::from_utf8_lossy(&o.stderr).to_string())
769→                        .unwrap_or_default();
770→                    return Err(Error::message(format!(
771→                        "container rm failed for running container {name}: {}",
772→                        stderr.trim()
773→                    )));
774→                }
775→                // Stopped/exited/unknown — ghost container, mark as zombie.
776→                tracing::warn!(
777→                    name,
778→                    ?status,
779→                    "container rm -f failed for stopped container, marking as zombie"
780→                );
781→                mark_zombie(name);
782→                return Ok(());
783→            },
784→            _ => {
785→                // Inspect failed (not found) — container is already gone,
786→                // mark as zombie so it's filtered from stale list results.
787→                mark_zombie(name);
788→                return Ok(());
789→            },
790→        }
791→    }
792→    for cli in OCI_COMPATIBLE_CLIS {
793→        if !is_cli_available(cli) {
794→            continue;
795→        }
796→        let output = tokio::process::Command::new(cli)
797→            .args(["rm", "-f", name])
798→            .output()
799→            .await?;
800→        if !output.status.success() {
801→            let stderr = String::from_utf8_lossy(&output.stderr);
802→            return Err(Error::message(format!(
803→                "{cli} rm failed for {name}: {}",
804→                stderr.trim()
805→            )));
806→        }
807→        unmark_zombie(name);
808→        return Ok(());
809→    }
810→    Err(Error::message(format!(
811→        "no container CLI available to remove {name}"
812→    )))
813→}
814→
815→/// Restart the container daemon. For Apple Container this runs
816→/// `container system stop` followed by `container system start`.
817→/// For Docker it runs `docker restart` on the Docker daemon socket
818→/// (equivalent to `systemctl restart docker` but works cross-platform).
819→///
820→/// This clears ghost containers and corrupted daemon state.
821→pub async fn restart_container_daemon() -> Result<()> {
822→    if is_cli_available("container") {
823→        let stop = tokio::process::Command::new("container")
824→            .args(["system", "stop"])
825→            .output()
826→            .await?;
827→        if !stop.status.success() {
828→            let stderr = String::from_utf8_lossy(&stop.stderr);
829→            return Err(Error::message(format!(
830→                "container system stop failed: {}",
831→                stderr.trim()
832→            )));
833→        }
834→        let start = tokio::process::Command::new("container")
835→            .args(["system", "start"])
836→            .output()
837→            .await?;
838→        if !start.status.success() {
839→            let stderr = String::from_utf8_lossy(&start.stderr);
840→            return Err(Error::message(format!(
841→                "container system start failed: {}",
842→                stderr.trim()
843→            )));
844→        }
845→        clear_zombies();
846→        return Ok(());
847→    }
848→    // Docker/Podman: best-effort prune of stopped containers.
849→    for cli in OCI_COMPATIBLE_CLIS {
850→        if !is_cli_available(cli) {
851→            continue;
852→        }
853→        let _ = tokio::process::Command::new(cli)
854→            .args(["container", "prune", "-f"])
855→            .output()
856→            .await;
857→        return Ok(());
858→    }
859→    Err(Error::message(
860→        "no container CLI available to restart daemon",
861→    ))
862→}
863→
864→pub(crate) fn apple_container_status_from_inspect(stdout: &str) -> Option<&'static str> {
865→    let inspect = stdout.trim();
866→    if inspect.is_empty() || inspect == "[]" {
867→        return None;
868→    }
869→
870→    if inspect.contains(r#""status":"running""#) {
871→        return Some("running");
872→    }
873→
874→    if inspect.contains(r#""status":"stopped""#) || inspect.contains(r#""status":"exited""#) {
875→        return Some("stopped");
876→    }
877→
878→    None
879→}
880→
881→pub(crate) fn is_apple_container_service_error(stderr: &str) -> bool {
882→    stderr.contains("XPC connection error") || stderr.contains("Connection invalid")
883→}
884→
885→pub(crate) fn is_apple_container_exists_error(stderr: &str) -> bool {
886→    stderr.contains("already exists") || stderr.contains("exists: \"container with id")
887→}
888→
889→pub(crate) fn is_apple_container_daemon_stale_error(text: &str) -> bool {
890→    // Both patterns are required — `NSPOSIXErrorDomain` alone can appear in
891→    // benign log-fetching errors (Code=2 "No such file or directory") when a
892→    // container vanishes. The stale-daemon signature is specifically EINVAL:
893→    // `NSPOSIXErrorDomain Code=22 "Invalid argument"`.
894→    text.contains("NSPOSIXErrorDomain") && text.contains("Invalid argument")
895→}
896→
897→pub(crate) fn is_apple_container_corruption_error(stderr: &str) -> bool {
898→    let lower = stderr.to_ascii_lowercase();
899→    is_apple_container_service_error(stderr)
900→        || is_apple_container_exists_error(stderr)
901→        || is_apple_container_daemon_stale_error(stderr)
902→        || lower.contains("failed to bootstrap container")
903→        || lower.contains("config.json")
904→        || lower.contains("vm never booted")
905→}
906→
907→pub(crate) fn should_use_docker_backend(
908→    docker_cli_available: bool,
909→    docker_daemon_available: bool,
910→) -> bool {
911→    docker_cli_available && docker_daemon_available
912→}
913→
914→pub(crate) fn is_docker_daemon_available() -> bool {
915→    std::process::Command::new("docker")
916→        .args(["info", "--format", "{{.ServerVersion}}"])
917→        .stdout(std::process::Stdio::null())
918→        .stderr(std::process::Stdio::null())
919→        .status()
920→        .is_ok_and(|s| s.success())
921→}
922→
923→/// Check whether a CLI tool is available on PATH.
924→pub(crate) fn is_cli_available(name: &str) -> bool {
925→    std::process::Command::new(name)
926→        .arg("--version")
927→        .stdout(std::process::Stdio::null())
928→        .stderr(std::process::Stdio::null())
929→        .status()
930→        .is_ok_and(|s| s.success())
931→}
932→
933→/// Return the name of the container CLI to use for OCI image operations
934→/// (`docker run`, `docker build`, etc.).
935→///
936→/// Prefers `podman` (daemonless) when available, falls back to `docker`.
937→/// The result is cached after the first call.
938→pub fn container_cli() -> &'static str {
939→    static CLI: std::sync::OnceLock<&str> = std::sync::OnceLock::new();
940→    CLI.get_or_init(|| {
941→        if is_cli_available("podman") {
942→            "podman"
943→        } else {
944→            "docker"
945→        }
946→    })
947→}
