    router.emit_event(SandboxEvent::Provisioning {
        container: "test".into(),
        packages: vec!["curl".into()],
    });

    let event = rx.try_recv().unwrap();
    match event {
        SandboxEvent::Provisioning {
            container,
            packages,
        } => {
            assert_eq!(container, "test");
            assert_eq!(packages, vec!["curl".to_string()]);
        },
